 1	import React, { FC, FormEvent } from 'react';
 2	
 3	import { ManagedColumn } from '@openshift-console/dynamic-plugin-sdk';
 4	import {
 5	  DataListCell,
 6	  DataListCheck,
 7	  DataListItem,
 8	  DataListItemCells,
 9	  DataListItemRow,
10	} from '@patternfly/react-core';
11	
12	import { NAME_COLUMN_ID } from './constants';
13	
14	type DataListRowProps = {
15	  checkedColumns: Set<string>;
16	  column: ManagedColumn;
17	  disableUncheckedRow: boolean;
18	  inputId: string;
19	  onChange: (event: FormEvent<HTMLInputElement>, checked: boolean) => void;
20	};
21	
22	const DataListRow: FC<DataListRowProps> = ({
23	  checkedColumns,
24	  column,
25	  disableUncheckedRow,
26	  inputId,
27	  onChange,
28	}) => (
29	  <DataListItem
30	    aria-labelledby={`table-column-management-item-${column.id}`}
31	    className="data-list-row-item pf-v6-c-data-list__item--transparent-bg"
32	    key={column.id}
33	  >
34	    <DataListItemRow>
35	      <DataListCheck
36	        isDisabled={
37	          (disableUncheckedRow && !checkedColumns.has(column.id)) || column.id === NAME_COLUMN_ID
38	        }
39	        aria-labelledby={`table-column-management-item-${column.id}`}
40	        checked={checkedColumns.has(column.id)}
41	        id={inputId}
42	        name={column.title}
43	        onChange={onChange}
44	      />
45	      <DataListItemCells
46	        dataListCells={[
47	          <DataListCell id={`table-column-management-item-${column.id}`} key={column.id}>
48	            <label className="co-label--plain" htmlFor={inputId}>
49	              {column.title}
50	            </label>
51	          </DataListCell>,
52	        ]}
53	      />
54	    </DataListItemRow>
55	  </DataListItem>
56	);
57	
58	export default DataListRow;

